static constexpr size_t PALETTE_MAX_RESULTS = 100;
static constexpr size_t PALETTE_MAX_QUERY = 256;

struct PaletteState {
    bool visible = false;
    PaletteMode mode = PaletteMode::AutoDetect;

    // Input
    wchar_t query[PALETTE_MAX_QUERY] = {0};
    size_t query_len = 0;
    size_t cursor_pos = 0;

    // Results
    PaletteResult results[PALETTE_MAX_RESULTS];
    size_t result_count = 0;

    // Selection
    int selected_index = 0;
    int hovered_index = -1;  // For hover highlighting
    int scroll_offset = 0;

    // Multi-select
    bool multi_select_mode = false;
    size_t selected_count = 0;

    // Display text cache for non-wchar_t sources
    wchar_t display_cache[PALETTE_MAX_RESULTS][512];

    // UTF-8 path cache for file/remote results
    char path_cache[PALETTE_MAX_RESULTS][512];

    // Inline input mode (for commands requiring input like Create Branch)
    bool input_mode = false;
    const PaletteCommand* pending_command = nullptr;

    // Animation (simplified single-layer model: scale entire palette with blur)
    bool animating = false;
    bool dismissing = false;          // True if animating out

    // Spring animation state (single spring for scale, opacity follows progress)
    float anim_scale = 1.0f;          // 0.92 → 1.0 (spring physics)
    float anim_velocity = 0.0f;       // Spring velocity
    float anim_opacity = 0.0f;        // 0 → 1 (linear, tied to spring progress)
    float anim_blur = 0.0f;           // BLUR_RADIUS → 0 (tied to opacity)

    bool is_animating = false;        // AnimationScheduler registration tracking
};

