// ============================================================================
// Layout Calculation Helper
// ============================================================================

// Returns the height of the results section and count of visible items
// This accounts for MAX_VISIBLE_ITEMS cap and group headers in AutoDetect mode
struct ResultsLayout {
    float height;
    int visible_count;
};

// Minimum height for empty state area (message + hint + padding)
static constexpr float EMPTY_STATE_HEIGHT = 64.0f;

// Check if items [from_index, to_index] fit within the visible area
static bool items_fit_in_view(int from_index, int to_index) {
    using namespace CommandPalette;

    float height = 0.0f;
    float max_height = MAX_VISIBLE_ITEMS * ITEM_HEIGHT;
    PaletteResultType last_type = (PaletteResultType)-1;

    for (int i = from_index; i <= to_index && i < (int)g_palette.result_count; i++) {
        float item_height = ITEM_HEIGHT;

        if (g_palette.mode == PaletteMode::AutoDetect && g_palette.results[i].type != last_type) {
            item_height += GROUP_HEADER_HEIGHT;
            last_type = g_palette.results[i].type;
        }

        height += item_height;
        if (height > max_height) return false;
    }

    return true;
}

static ResultsLayout calculate_results_layout() {
    using namespace CommandPalette;
    ResultsLayout layout = {0.0f, 0};

    if (g_palette.result_count == 0) {
        // Reserve space for empty state message when user has typed a query
        if (g_palette.query_len > 0 && !g_palette.input_mode) {
            layout.height = EMPTY_STATE_HEIGHT;
        }
        return layout;
    }

    PaletteResultType last_type = (PaletteResultType)-1;
    for (size_t i = 0; i < g_palette.result_count && layout.visible_count < (int)MAX_VISIBLE_ITEMS; i++) {
        // Add group header height when type changes in AutoDetect mode
        if (g_palette.mode == PaletteMode::AutoDetect && g_palette.results[i].type != last_type) {
            layout.height += GROUP_HEADER_HEIGHT;
            last_type = g_palette.results[i].type;
        }
        layout.height += ITEM_HEIGHT;
        layout.visible_count++;
    }

    return layout;
}

