static void palette_search_commands() {
    size_t count = command_registry_count();

    for (size_t i = 0; i < count && g_palette.result_count < PALETTE_MAX_RESULTS; i++) {
        const PaletteCommand* cmd = command_registry_get(i);
        if (!cmd) continue;

        // Skip commands that aren't available in current context
        if (cmd->is_available && !cmd->is_available()) continue;

        // Match against command name
        FuzzyMatchResult match = fuzzy_match(g_palette.query, cmd->name);

        // Also try matching against command ID (e.g., "git.stageAll")
        if (!match.matched) {
            wchar_t id_wide[128];
            utf8_to_wide(cmd->id, id_wide, 128);
            match = fuzzy_match(g_palette.query, id_wide);
        }

        if (match.matched || g_palette.query_len == 0) {
            PaletteResult& r = g_palette.results[g_palette.result_count++];
            r.type = PaletteResultType::Command;
            r.score = match.score;
            r.match_mask = match.match_mask;
            r.command = cmd;
            r.display_text = cmd->name;
            r.shortcut = cmd->shortcut;
            r.selected = false;
        }
    }
}

