static void palette_search_branches() {
    size_t count = palette_get_branch_count();

    for (size_t i = 0; i < count && g_palette.result_count < PALETTE_MAX_RESULTS; i++) {
        const GitRef* ref = palette_get_branch(i);

        // Convert branch name to wide string
        wchar_t name_wide[Git::MAX_REF_NAME];
        utf8_to_wide(ref->name, name_wide, Git::MAX_REF_NAME);

        FuzzyMatchResult match = fuzzy_match(g_palette.query, name_wide);

        if (match.matched || g_palette.query_len == 0) {
            PaletteResult& r = g_palette.results[g_palette.result_count];
            r.type = PaletteResultType::Branch;
            r.score = match.score;
            r.match_mask = match.match_mask;
            r.branch = ref;

            // Store display text in cache
            wcscpy_s(g_palette.display_cache[g_palette.result_count], 512, name_wide);
            r.display_text = g_palette.display_cache[g_palette.result_count];
            r.shortcut = nullptr;
            r.selected = false;

            g_palette.result_count++;
        }
    }
}

