// Convert SHA bytes to hex string
static void sha_to_hex(const uint8_t* sha, char* hex_out, size_t hex_size) {
    static const char hex_chars[] = "0123456789abcdef";
    size_t max_bytes = (hex_size - 1) / 2;
    if (max_bytes > Git::SHA1_RAW_SIZE) max_bytes = Git::SHA1_RAW_SIZE;
    for (size_t i = 0; i < max_bytes; i++) {
        hex_out[i * 2] = hex_chars[(sha[i] >> 4) & 0x0F];
        hex_out[i * 2 + 1] = hex_chars[sha[i] & 0x0F];
    }
    hex_out[max_bytes * 2] = '\0';
}

static void palette_search_commits() {
    // Limit to recent 1000 commits for performance
    size_t total_count = palette_get_commit_count();
    size_t search_limit = (total_count < 1000) ? total_count : 1000;

    for (size_t i = 0; i < search_limit && g_palette.result_count < PALETTE_MAX_RESULTS; i++) {
        const CommitMeta* commit = palette_get_commit(i);
        if (!commit) continue;

        const char* message = palette_get_commit_message(i);
        if (!message) continue;

        // Get SHA as hex for matching
        char sha_hex[41];
        sha_to_hex(commit->sha, sha_hex, sizeof(sha_hex));

        // Convert message to wide for fuzzy matching
        wchar_t message_wide[512];
        utf8_to_wide(message, message_wide, 512);

        // Also try matching against SHA prefix
        wchar_t sha_wide[41];
        utf8_to_wide(sha_hex, sha_wide, 41);

        FuzzyMatchResult match = fuzzy_match(g_palette.query, message_wide);
        bool matched_message = match.matched;
        if (!match.matched) {
            match = fuzzy_match(g_palette.query, sha_wide);
        }

        if (match.matched || g_palette.query_len == 0) {
            size_t idx = g_palette.result_count;
            PaletteResult& r = g_palette.results[idx];
            r.type = PaletteResultType::Commit;
            r.score = match.score;
            r.commit_index = i;

            // Format display: "sha_short - message"
            char short_sha[8];
            strncpy_s(short_sha, sizeof(short_sha), sha_hex, 7);
            short_sha[7] = '\0';

            // Display format adds "sha_short - " prefix (10 chars) before message.
            // match_mask is 64 bits; shifting by PREFIX_LEN means we can only
            // preserve highlights for the first (64 - PREFIX_LEN) chars of the
            // message. Mask before shift to make the truncation explicit (so
            // higher bits don't undefined-behavior into something garbage on
            // future ISA changes).
            constexpr size_t PREFIX_LEN = 10;  // "abc1234 - "
            constexpr uint64_t MESSAGE_MASK_BITS = (1ULL << (64 - PREFIX_LEN)) - 1;
            if (matched_message && match.match_mask != 0) {
                r.match_mask = (match.match_mask & MESSAGE_MASK_BITS) << PREFIX_LEN;
            } else {
                r.match_mask = match.match_mask;  // SHA match - no offset needed
            }

            char display_utf8[512];
            snprintf(display_utf8, sizeof(display_utf8), "%s - %.60s%s",
                     short_sha, message, (strlen(message) > 60) ? "..." : "");
            utf8_to_wide(display_utf8, g_palette.display_cache[idx], 512);
            r.display_text = g_palette.display_cache[idx];
            r.shortcut = nullptr;
            r.selected = false;

            g_palette.result_count++;
        }
    }
}

// Sort results by score (descending)
static int compare_results(const void* a, const void* b) {
    const PaletteResult* ra = (const PaletteResult*)a;
    const PaletteResult* rb = (const PaletteResult*)b;

    // First by type (for grouping in mixed mode)
    if (ra->type != rb->type) {
        return (int)ra->type - (int)rb->type;
    }

    // Then by score (descending)
    return rb->score - ra->score;
}

static void palette_update_search() {
    g_palette.result_count = 0;
    g_palette.selected_index = 0;
    g_palette.scroll_offset = 0;

    switch (g_palette.mode) {
        case PaletteMode::Commands:
            palette_search_commands();
            break;

        case PaletteMode::Files:
            palette_search_files();
            break;

        case PaletteMode::Branches:
            palette_search_branches();
            break;

        case PaletteMode::Remotes:
            palette_search_remotes();
            break;

        case PaletteMode::Commits:
            palette_search_commits();
            break;

        case PaletteMode::AutoDetect:
        default:
            // Search all scopes
            palette_search_commands();
            palette_search_branches();
            palette_search_files();
            palette_search_remotes();
            palette_search_commits();  // Include commits in auto-detect results
            break;
    }

    // Sort results
    if (g_palette.result_count > 1) {
        qsort(g_palette.results, g_palette.result_count, sizeof(PaletteResult), compare_results);
    }
}

// ============================================================================
// Mode Detection
// ============================================================================

static void palette_detect_mode() {
    if (g_palette.query_len == 0) {
        g_palette.mode = PaletteMode::AutoDetect;
        return;
    }

    wchar_t first = g_palette.query[0];

    switch (first) {
        case L'>':
            g_palette.mode = PaletteMode::Commands;
            // Shift query to remove prefix
            if (g_palette.query_len > 1) {
                wmemmove(g_palette.query, g_palette.query + 1, g_palette.query_len);
                g_palette.query_len--;
                if (g_palette.cursor_pos > 0) g_palette.cursor_pos--;
            } else {
                g_palette.query[0] = L'\0';
                g_palette.query_len = 0;
                g_palette.cursor_pos = 0;
            }
            break;

        case L'/':
            g_palette.mode = PaletteMode::Files;
            if (g_palette.query_len > 1) {
                wmemmove(g_palette.query, g_palette.query + 1, g_palette.query_len);
                g_palette.query_len--;
                if (g_palette.cursor_pos > 0) g_palette.cursor_pos--;
            } else {
                g_palette.query[0] = L'\0';
                g_palette.query_len = 0;
                g_palette.cursor_pos = 0;
            }
            break;

        case L'@':
            g_palette.mode = PaletteMode::Branches;
            if (g_palette.query_len > 1) {
                wmemmove(g_palette.query, g_palette.query + 1, g_palette.query_len);
                g_palette.query_len--;
                if (g_palette.cursor_pos > 0) g_palette.cursor_pos--;
            } else {
                g_palette.query[0] = L'\0';
                g_palette.query_len = 0;
                g_palette.cursor_pos = 0;
            }
            break;

        case L'#':
            g_palette.mode = PaletteMode::Commits;
            if (g_palette.query_len > 1) {
                wmemmove(g_palette.query, g_palette.query + 1, g_palette.query_len);
                g_palette.query_len--;
                if (g_palette.cursor_pos > 0) g_palette.cursor_pos--;
            } else {
                g_palette.query[0] = L'\0';
                g_palette.query_len = 0;
                g_palette.cursor_pos = 0;
            }
            break;

        case L':':
            g_palette.mode = PaletteMode::Remotes;
            if (g_palette.query_len > 1) {
                wmemmove(g_palette.query, g_palette.query + 1, g_palette.query_len);
                g_palette.query_len--;
                if (g_palette.cursor_pos > 0) g_palette.cursor_pos--;
            } else {
                g_palette.query[0] = L'\0';
                g_palette.query_len = 0;
                g_palette.cursor_pos = 0;
            }
            break;

        default:
            // Keep current mode or auto-detect
            break;
    }
}

// ============================================================================
// Command Execution
// ============================================================================

// Enter inline input mode for commands requiring input
static void palette_enter_input_mode(const PaletteCommand* cmd) {
    g_palette.input_mode = true;
    g_palette.pending_command = cmd;

    // Clear query for new input
    g_palette.query[0] = L'\0';
    g_palette.query_len = 0;
    g_palette.cursor_pos = 0;

    // Clear results
    g_palette.result_count = 0;
    g_palette.selected_index = 0;
    g_palette.scroll_offset = 0;

    InvalidateRect(g_main_window, nullptr, FALSE);
}

// Exit inline input mode without executing
static void palette_exit_input_mode() {
    g_palette.input_mode = false;
    g_palette.pending_command = nullptr;

    // Clear query and restore normal mode
    g_palette.query[0] = L'\0';
    g_palette.query_len = 0;
    g_palette.cursor_pos = 0;
    g_palette.mode = PaletteMode::AutoDetect;

    // Refresh search to show commands again
    palette_update_search();
    InvalidateRect(g_main_window, nullptr, FALSE);
}

